1	/**
2	 * LayerInfinite API — coach-session-tracker.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Session-level coaching limits for the LLM Coach.
5	 *
6	 * Rules:
7	 *   - Max 3 coaching injections per agent session
8	 *   - Sessions expire after 30 minutes of inactivity
9	 *   - Coaching retires automatically when a task_type has
10	 *     ≥ 50 outcomes (statistical scoring is sufficient)
11	 *
12	 * Durability:
13	 *   - In-memory Map is the primary fast path
14	 *   - DB-backed fallback prevents cap reset on server restart:
15	 *     writes are fire-and-forget, reads happen only on cold miss
16	 * ══════════════════════════════════════════════════════════════
17	 */
18	
19	import { supabase } from './supabase.js';
20	
21	interface CoachSessionState {
22	  agentId: string;
23	  sessionStart: number;
24	  coachingCount: number;
25	  /** Per-task-type outcome counts known at coaching time. */
26	  taskOutcomeCounts: Map<string, number>;
27	}
28	
29	const MAX_COACHING_PER_SESSION = 3;
30	const SESSION_TTL_MS = 30 * 60 * 1000;
31	const RETIRE_OUTCOME_THRESHOLD = 50;
32	const CLEANUP_INTERVAL_MS = 5 * 60 * 1000;
33	
34	// ── DB helpers (fire-and-forget, never block the hot path) ────
35	
36	async function persistCoachingToDB(agentId: string, sessionStart: number, count: number): Promise<void> {
37	    try {
38	        await supabase
39	            .from('coach_session_state')
40	            .upsert({
41	                agent_id: agentId,
42	                session_start: new Date(sessionStart).toISOString(),
43	                coaching_count: count,
44	                last_coaching_at: new Date().toISOString(),
45	            }, {
46	                onConflict: 'agent_id,session_start',
47	                ignoreDuplicates: false,
48	            });
49	    } catch {
50	        // Fire-and-forget — DB unavailability must never block coaching
51	    }
52	}
53	
54	async function recoverCountFromDB(agentId: string, sessionStart: number): Promise<number> {
55	    try {
56	        const { data } = await supabase
57	            .from('coach_session_state')
58	            .select('coaching_count')
59	            .eq('agent_id', agentId)
60	            .eq('session_start', new Date(sessionStart).toISOString())
61	            .maybeSingle();
62	
63	        return typeof (data as any)?.coaching_count === 'number' ? (data as any).coaching_count : -1;
64	    } catch {
65	        return -1;
66	    }
67	}
68	
69	async function cleanupDB(): Promise<void> {
70	    try {
71	        const cutoff = new Date(Date.now() - SESSION_TTL_MS).toISOString();
72	        await supabase
73	            .from('coach_session_state')
74	            .delete()
75	            .lt('session_start', cutoff);
76	    } catch {
77	        // Best-effort — stale rows are harmless (session_start won't match on recovery)
78	    }
79	}
80	
81	export class CoachSessionTracker {
82	  private readonly sessions = new Map<string, CoachSessionState>();
83	  private cleanupTimer: ReturnType<typeof setInterval> | null = null;
84	
85	  /**
86	   * Check whether coaching is allowed for this agent + task_type.
87	   * Returns false if the session cap (3) is reached or if the
88	   * task_type has enough historical outcomes for statistical scoring.
89	   * Falls back to DB on cold start when in-memory session is missing.
90	   */
91	  async canCoach(agentId: string, taskType: string, taskOutcomeCount = 0): Promise<boolean> {
92	    this.cleanExpired();
93	
94	    if (taskOutcomeCount >= RETIRE_OUTCOME_THRESHOLD) return false;
95	
96	    const memState = this.sessions.get(agentId);
97	    if (memState) {
98	      return memState.coachingCount < MAX_COACHING_PER_SESSION;
99	    }
100	
101	    // Cold start — try DB recovery before creating a fresh session
102	    const recoveredCount = await recoverCountFromDB(agentId, Date.now());
103	    if (recoveredCount >= 0 && recoveredCount < MAX_COACHING_PER_SESSION) {
104	      // Recover session state from DB floor
105	      const recovered: CoachSessionState = {
106	        agentId,
107	        sessionStart: Date.now(),
108	        coachingCount: recoveredCount,
109	        taskOutcomeCounts: new Map(),
110	      };
111	      this.sessions.set(agentId, recovered);
112	      return true;
113	    }
114	
115	    return true; // no session at all — coaching is allowed
116	  }
117	
118	  /**
119	   * Record a coaching injection. Returns true if recorded,
120	   * false if the cap was already reached.
121	   * Persists to DB as fire-and-forget for cold-start recovery.
122	   */
123	  recordCoaching(agentId: string, taskType: string): boolean {
124	    this.cleanExpired();
125	
126	    const state = this.getOrCreate(agentId);
127	    if (state.coachingCount >= MAX_COACHING_PER_SESSION) return false;
128	
129	    state.coachingCount++;
130	    state.taskOutcomeCounts.set(
131	      taskType,
132	      (state.taskOutcomeCounts.get(taskType) ?? 0) + 1,
133	    );
134	
135	    // Fire-and-forget DB persistence — never blocks the hot path
136	    persistCoachingToDB(agentId, state.sessionStart, state.coachingCount);
137	
138	    return true;
139	  }
140	
141	  /**
142	   * Update the known outcome count for a task_type.
143	   * Once ≥ 50, coaching retires for that task_type permanently.
144	   */
145	  setTaskOutcomeCount(agentId: string, taskType: string, count: number): void {
146	    const state = this.getOrCreate(agentId);
147	    state.taskOutcomeCounts.set(taskType, count);
148	  }
149	
150	  /** Remaining coaching slots for this agent's current session. */
151	  remainingCoachingSlots(agentId: string): number {
152	    this.cleanExpired();
153	    const state = this.sessions.get(agentId);
154	    if (!state) return MAX_COACHING_PER_SESSION;
155	    return Math.max(0, MAX_COACHING_PER_SESSION - state.coachingCount);
156	  }
157	
158	  get activeSessionCount(): number {
159	    this.cleanExpired();
160	    return this.sessions.size;
161	  }
162	
163	  // ── Private ──────────────────────────────────────────────────
164	
165	  private getOrCreate(agentId: string): CoachSessionState {
166	    const existing = this.sessions.get(agentId);
167	    if (existing) return existing;
168	
169	    const state: CoachSessionState = {
170	      agentId,
171	      sessionStart: Date.now(),
172	      coachingCount: 0,
173	      taskOutcomeCounts: new Map(),
174	    };
175	    this.sessions.set(agentId, state);
176	
177	    if (!this.cleanupTimer) {
178	      this.cleanupTimer = setInterval(() => this.cleanExpired(), CLEANUP_INTERVAL_MS).unref();
179	    }
180	
181	    return state;
182	  }
183	
184	  private cleanExpired(): void {
185	    const cutoff = Date.now() - SESSION_TTL_MS;
186	    for (const [id, state] of this.sessions) {
187	      if (state.sessionStart < cutoff) {
188	        this.sessions.delete(id);
189	      }
190	    }
191	    if (this.sessions.size === 0 && this.cleanupTimer) {
192	      clearInterval(this.cleanupTimer);
193	      this.cleanupTimer = null;
194	    }
195	    // Also cleanup stale DB rows (best-effort, throttled by the 5-min cleanup interval)
196	    cleanupDB().catch(() => {});
197	  }
198	}
199	
200	/** Singleton instance for the process. */
201	export const coachTracker = new CoachSessionTracker();
202

1	/**
2	 * LayerInfinite API — llm-coach.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * LLM-based coaching that fires on failed actions.
5	 *
6	 * Model: gpt-4o-mini (~$0.15/1M input tokens)
7	 * Cap:    3 coaching injections per agent session
8	 * Retire: when task_type has ≥ 50 historical outcomes
9	 * Timeout: 3s — on timeout, agent proceeds without coaching
10	 *
11	 * Integration point: called from the MCP gateway's enrichment
12	 * engine when an agent reports a failure. The coaching message
13	 * is injected into the next tools/list enrichment as a
14	 * "LI Note:" prefix.
15	 * ══════════════════════════════════════════════════════════════
16	 */
17	
18	import { coachTracker } from './coach-session-tracker.js';
19	import type { ActionScore } from './supabase.js';
20	
21	// ── Types ──────────────────────────────────────────────────────
22	
23	export interface CoachingInput {
24	  agentId: string;
25	  customerId: string;
26	  /** The task the agent was attempting (e.g. "build_failed"). */
27	  taskType: string;
28	  /** The action that just failed. */
29	  failedActionName: string;
30	  /** Error details if available. */
31	  errorMessage?: string;
32	  /** All tools the agent can see (names + descriptions). */
33	  availableTools: Array<{ name: string; description: string }>;
34	  /** Historical scores for this task_type. */
35	  historicalScores: Pick<
36	    ActionScore,
37	    'action_name' | 'raw_success_rate' | 'total_attempts' | 'trend_delta'
38	  >[];
39	  /** Number of recorded outcomes for this task_type. */
40	  taskOutcomeCount: number;
41	}
42	
43	// ── Constants ──────────────────────────────────────────────────
44	
45	const COACH_TIMEOUT_MS = 3_000;
46	const OPENAI_CHAT_URL = 'https://api.openai.com/v1/chat/completions';
47	
48	// ── Public API ─────────────────────────────────────────────────
49	
50	/**
51	 * Generate a coaching message for a failed action.
52	 * Returns null if coaching is disabled, capped, retired, or errors.
53	 */
54	export async function generateCoachingMessage(
55	  input: CoachingInput,
56	): Promise<string | null> {
57	  // ── 1. Pre-flight checks ──────────────────────────────────
58	  const apiKey = process.env.OPENAI_API_KEY;
59	  if (!apiKey) return null;
60	
61	  if (!(await coachTracker.canCoach(input.agentId, input.taskType, input.taskOutcomeCount))) {
62	    return null;
63	  }
64	
65	  // ── 2. Build scoring summary ───────────────────────────────
66	  const relevantScores = input.historicalScores
67	    .filter((s) => s.action_name !== input.failedActionName)
68	    .sort((a, b) => (b.raw_success_rate ?? 0) - (a.raw_success_rate ?? 0))
69	    .slice(0, 5);
70	
71	  if (relevantScores.length === 0) return null; // No alternatives to suggest
72	
73	  const scoreLines = relevantScores.map((s) => {
74	    const pct = Math.round((s.raw_success_rate ?? 0) * 100);
75	    const attempts = s.total_attempts ?? 0;
76	    const trend = s.trend_delta != null
77	      ? s.trend_delta > 0 ? 'improving' : s.trend_delta < 0 ? 'declining' : 'stable'
78	      : null;
79	    let line = `- ${s.action_name}: ${pct}% success (${attempts} outcomes)`;
80	    if (trend) line += `, trend: ${trend}`;
81	    return line;
82	  }).join('\n');
83	
84	  // ── 3. Build prompt ────────────────────────────────────────
85	  const systemPrompt =
86	    'You are a concise engineering coach. ' +
87	    'Given a failed action and historical performance data, suggest an alternative ' +
88	    'in exactly 1-2 sentences. Be specific — name the tool and its success rate. ' +
89	    'Do not apologize, explain your reasoning, or use filler words. ' +
90	    'Start directly with the coaching note.';
91	
92	  const userPrompt =
93	    `The agent just failed executing "${input.failedActionName}" for task "${input.taskType}".` +
94	    (input.errorMessage ? ` Error: ${input.errorMessage}.` : '') +
95	    `\n\nHistorical performance for "${input.taskType}":\n${scoreLines}` +
96	    `\n\nAvailable tools: ${input.availableTools.map((t) => t.name).join(', ')}` +
97	    `\n\nProvide a 1-2 sentence coaching note suggesting the best alternative. ` +
98	    `Format: "LI Note: [your coaching]". Include the recommended tool's name and success rate.`;
99	
100	  // ── 4. Call gpt-4o-mini with timeout ───────────────────────
101	  try {
102	    const controller = new AbortController();
103	    const timeoutId = setTimeout(() => controller.abort(), COACH_TIMEOUT_MS);
104	
105	    const response = await fetch(OPENAI_CHAT_URL, {
106	      method: 'POST',
107	      headers: {
108	        'Authorization': `Bearer ${apiKey}`,
109	        'Content-Type': 'application/json',
110	      },
111	      body: JSON.stringify({
112	        model: 'gpt-4o-mini',
113	        messages: [
114	          { role: 'system', content: systemPrompt },
115	          { role: 'user', content: userPrompt },
116	        ],
117	        max_tokens: 120,
118	        temperature: 0.4,
119	      }),
120	      signal: controller.signal,
121	    });
122	
123	    clearTimeout(timeoutId);
124	
125	    if (!response.ok) {
126	      console.warn(
127	        '[llm-coach] OpenAI API error:',
128	        response.status,
129	        response.statusText,
130	      );
131	      return null;
132	    }
133	
134	    const data = (await response.json()) as {
135	      choices?: Array<{ message?: { content?: string } }>;
136	    };
137	
138	    const content = data.choices?.[0]?.message?.content?.trim();
139	    if (!content) return null;
140	
141	    // ── 5. Record + return ──────────────────────────────────
142	    coachTracker.recordCoaching(input.agentId, input.taskType);
143	
144	    // Ensure "LI Note:" prefix is present
145	    if (!content.startsWith('LI Note:')) {
146	      return `LI Note: ${content}`;
147	    }
148	    return content;
149	  } catch (err: any) {
150	    if (err.name === 'AbortError') {
151	      console.warn('[llm-coach] OpenAI call timed out after 3s — skipping coaching');
152	    } else {
153	      console.warn('[llm-coach] OpenAI call failed:', err.message);
154	    }
155	    return null;
156	  }
157	}
