221	            version: SERVER_VERSION,
222	          };
223	
224	          return {
225	            contents: [
226	              {
227	                uri,
228	                mimeType: 'text/plain',
229	                text: JSON.stringify(status, null, 2),
230	              },
231	            ],
232	          };
233	        }
234	
235	        if (uri === 'li://gateway/config') {
236	          return {
237	            contents: [
238	              {
239	                uri,
240	                mimeType: 'application/json',
241	                text: JSON.stringify(
242	                  {
243	                    mode: config.mode ?? 'bootstrap',
244	                    environment: config.environment,
245	                    shadowMode: config.shadowMode,
