247	                    modeOverrides: Object.fromEntries(config.modeOverrides),
248	                    apiKey: '[REDACTED]',
249	                    baseUrl: config.baseUrl,
250	                    adminEnabled: config.adminKey !== null,
251	                  },
252	                  null,
253	                  2,
254	                ),
255	              },
256	            ],
257	          };
258	        }
259	
260	          if (uri === dashboardResource.uri) {
261	            const result = await dashboardResource.handler();
262	            return { contents: result.contents };
263	          }
264	
265	          if (uri === docsResource.uri) {
266	            const result = await docsResource.handler();
267	            return { contents: result.contents };
268	          }
269	
270	        return {
271	          contents: [
272	            {
273	              uri,
274	              mimeType: 'text/plain',
275	              text: `Unknown resource: ${uri}`,
276	            },
277	          ],
278	        };
279	      } catch (err) {
280	        log.error('resources/read failed', { uri, error: err instanceof Error ? err.message : String(err) });
281	        return {
282	          contents: [{ uri, mimeType: 'text/plain', text: 'Error reading resource' }],
