1	/**
2	 * LayerInfinite MCP Server — fail-open.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * 3-Layer failure protection with circuit breaker.
5	 *
6	 * Layer 1: Async logging fails → write to local disk queue → retry with backoff
7	 * Layer 2: LI API unreachable → fail open → agent executes directly → queue on disk
8	 * Layer 3: Everything fails → agent executes as if LI doesn't exist → zero footprint
9	 *
10	 * Circuit breaker: 3 consecutive upstream failures → open for 60s → half-open probe
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { writeFile, mkdir, readFile, unlink } from 'node:fs/promises';
15	import { join } from 'node:path';
16	import { randomUUID } from 'node:crypto';
17	import type { FailOpenState, OutcomePayload } from './types.js';
18	import { logger } from './logger.js';
19	
20	const log = logger.forTool('fail-open');
21	
22	const QUEUE_DIR = '.li-queue';
23	const CIRCUIT_BREAKER_THRESHOLD = 3;
24	const CIRCUIT_BREAKER_OPEN_MS = 60_000;
25	const MAX_QUEUE_RETRY_MS = 300_000; // 5 min max retry
26	const BASE_BACKOFF_MS = 1000;
27	
28	let processQueueRunning = false;
29	
30	export function createFailOpenState(): FailOpenState {
31	  return {
32	    upstreamFailures: new Map(),
33	    circuitBreakerOpen: new Map(),
34	    lastHealthCheck: new Map(),
35	    totalRequests: 0,
36	    passthroughRequests: 0,
37	  };
38	}
39	
40	/** Ensure queue directory exists. Returns the directory path. */
41	async function ensureQueueDir(): Promise<string> {
42	  await mkdir(QUEUE_DIR, { recursive: true });
43	  return QUEUE_DIR;
44	}
45	
46	// ── Layer 1: Disk queue for failed async logs ────────────────
47	
48	export interface QueuedEntry {
49	  id: string;
50	  payload: OutcomePayload;
51	  attempts: number;
52	  firstAttempt: number;
53	  lastAttempt: number;
54	}
55	
56	/**
57	 * Write an outcome to the local disk queue when LI API is unreachable.
58	 * Each entry is a separate JSON file for atomicity.
59	 */
60	export async function enqueueOutcome(payload: OutcomePayload): Promise<void> {
61	  const dir = await ensureQueueDir();
62	  const id = randomUUID();
63	  const entry: QueuedEntry = {
64	    id,
65	    payload,
66	    attempts: 0,
67	    firstAttempt: Date.now(),
68	    lastAttempt: Date.now(),
69	  };
70	  const path = join(dir, `${id}.json`);
71	  await writeFile(path, JSON.stringify(entry) + '\n', 'utf-8');
72	  log.info('Outcome queued to disk', { id, action: payload.action_name });
73	}
74	
75	/** List all queued entries sorted by first attempt (oldest first). */
76	export async function listQueuedEntries(): Promise<QueuedEntry[]> {
77	  const { readdir } = await import('node:fs/promises');
78	  const dir = await ensureQueueDir();
79	  const entries: QueuedEntry[] = [];
80	  try {
81	    const files = await readdir(dir);
82	    for (const file of files) {
83	      if (!file.endsWith('.json')) continue;
84	      try {
85	        const content = await readFile(join(dir, file), 'utf-8');
86	        entries.push(JSON.parse(content) as QueuedEntry);
87	      } catch {
88	        // Corrupt queue file — skip
89	      }
90	    }
91	  } catch {
92	    // Directory doesn't exist yet — no entries
93	  }
94	  return entries.sort((a, b) => a.firstAttempt - b.firstAttempt);
95	}
96	
97	/** Remove a queued entry by ID. */
98	export async function dequeueEntry(id: string): Promise<void> {
99	  const dir = await ensureQueueDir();
100	  try {
101	    await unlink(join(dir, `${id}.json`));
102	  } catch {
103	    // Already removed — fine
104	  }
105	}
106	
107	/** Update attempts on a queued entry. */
108	export async function updateQueuedEntry(entry: QueuedEntry): Promise<void> {
109	  const dir = await ensureQueueDir();
110	  await writeFile(join(dir, `${entry.id}.json`), JSON.stringify(entry) + '\n', 'utf-8');
111	}
112	
113	// ── Layer 2 & 3: Circuit breaker ─────────────────────────────
114	
115	/** Record a failure for an upstream server. Returns true if circuit breaker just opened. */
116	export function recordUpstreamFailure(state: FailOpenState, upstreamName: string): boolean {
117	  const current = state.upstreamFailures.get(upstreamName) ?? 0;
118	  const next = current + 1;
119	  state.upstreamFailures.set(upstreamName, next);
120	
121	  if (next >= CIRCUIT_BREAKER_THRESHOLD && !state.circuitBreakerOpen.get(upstreamName)) {
122	    state.circuitBreakerOpen.set(upstreamName, true);
123	    log.warn('Circuit breaker opened', { upstream: upstreamName, failures: next });
124	    return true;
125	  }
126	  return false;
127	}
128	
129	/** Record a success — resets failure count and closes circuit breaker. */
130	export function recordUpstreamSuccess(state: FailOpenState, upstreamName: string): void {
131	  state.upstreamFailures.set(upstreamName, 0);
132	  if (state.circuitBreakerOpen.get(upstreamName)) {
133	    state.circuitBreakerOpen.set(upstreamName, false);
134	    log.info('Circuit breaker closed', { upstream: upstreamName });
135	  }
136	}
137	
138	/** Probe half-open: check if enough time has passed to attempt a probe.
139	 *  Does NOT reset state — the caller must call recordUpstreamSuccess/Failure
140	 *  after the actual health check completes. */
141	export function probeCircuitBreaker(state: FailOpenState, upstreamName: string): boolean {
142	  const open = state.circuitBreakerOpen.get(upstreamName);
143	  if (!open) return false;
144	
145	  const lastCheck = state.lastHealthCheck.get(upstreamName) ?? 0;
146	  if (Date.now() - lastCheck < CIRCUIT_BREAKER_OPEN_MS) return false;
147	
148	  // Allow one probe through — caller is responsible for recording result
149	  state.circuitBreakerOpen.set(upstreamName, false);
150	  log.info('Circuit breaker half-open — probing', { upstream: upstreamName });
151	  return true;
152	}
153	
154	/** Check if circuit breaker is open for an upstream. */
155	export function isCircuitOpen(state: FailOpenState, upstreamName: string): boolean {
156	  return state.circuitBreakerOpen.get(upstreamName) ?? false;
157	}
158	
159	/** Update health check timestamp. */
160	export function updateHealthCheck(state: FailOpenState, upstreamName: string): void {
161	  state.lastHealthCheck.set(upstreamName, Date.now());
162	}
163	
164	// ── Retry queue processor ────────────────────────────────────
165	
166	export type QueueSender = (payload: OutcomePayload) => Promise<boolean>;
167	
168	/**
169	 * Process the disk queue with exponential backoff.
170	 * Returns the number of entries successfully sent.
171	 */
172	export async function processQueue(send: QueueSender): Promise<number> {
173	  if (processQueueRunning) {
174	    log.debug('Queue processor already running — skipping');
175	    return 0;
176	  }
177	  processQueueRunning = true;
178	
179	  try {
180	    const entries = await listQueuedEntries();
181	    let sent = 0;
182	
183	    for (const entry of entries) {
184	      const elapsed = Date.now() - entry.firstAttempt;
185	      if (elapsed > MAX_QUEUE_RETRY_MS) {
186	        log.warn('Queue entry expired', { id: entry.id, elapsed_ms: elapsed });
187	        await dequeueEntry(entry.id);
188	        continue;
189	      }
190	
191	      const success = await send(entry.payload);
192	      if (success) {
193	        await dequeueEntry(entry.id);
194	        sent++;
195	      } else {
196	        const updated: QueuedEntry = {
197	          ...entry,
198	          attempts: entry.attempts + 1,
199	          lastAttempt: Date.now(),
200	        };
201	        await updateQueuedEntry(updated);
202	      }
203	    }
204	
205	    return sent;
206	  } finally {
207	    processQueueRunning = false;
208	  }
209	}
210	
211	/**
212	 * Calculate backoff delay for a queue retry.
213	 * Exponential: min(base * 2^attempts, 5 min).
214	 */
215	export function backoffDelay(attempts: number): number {
216	  return Math.min(BASE_BACKOFF_MS * Math.pow(2, attempts), MAX_QUEUE_RETRY_MS);
217	}
218	
219	/** Get queue stats for monitoring. */
220	export async function getQueueStats(): Promise<{ count: number; oldestMs: number | null }> {
221	  const entries = await listQueuedEntries();
222	  return {
223	    count: entries.length,
224	    oldestMs: entries.length > 0 ? Date.now() - entries[0].firstAttempt : null,
225	  };
226	}
227	
228	// ── Queue processor lifecycle ────────────────────────────────
229	
230	/**
231	 * Start a periodic queue processor. Runs immediately on startup to drain any
232	 * entries left from a crash, then every `intervalMs` thereafter.
233	 * Returns a handle with `stop()` for clean shutdown.
234	 */
235	export function startQueueProcessor(
236	  send: QueueSender,
237	  intervalMs: number = 30_000,
238	): { stop: () => void } {
239	  // Drain on startup — catch crash leftovers immediately
240	  void processQueue(send);
241	
242	  const timer = setInterval(() => {
243	    void processQueue(send);
244	  }, intervalMs);
245	
246	  log.info('Queue processor started', { intervalMs });
247	
248	  return {
249	    stop: () => {
250	      clearInterval(timer);
251	      log.info('Queue processor stopped');
252	    },
253	  };
254	}
